+        assert!(!refs.is_empty());
+        assert_eq!(refs[0].from_stage, 1);
+        assert_eq!(refs[0].to_stage, 2);
+        assert!(refs[0].score > 0.5);
+    }
+
+    #[test]
+    fn test_empty_probe() {
+        let config = test_config();
+        let engine = StageVEngine::new(&config);
+
+        let query = vec![1.0; 8];
+        let candidates: Vec<Vec<f32>> = vec![];
+
